import { LlmModelType } from '@/constants/knowledge';
import { useTranslate } from '@/hooks/common-hooks';
import { useSelectLlmOptionsByModelType } from '@/hooks/llm-hooks';
import { Form, Select, Switch } from 'antd';
import { camelCase } from 'lodash';
import { useMemo } from 'react';

const enum DocumentType {
  DeepDOC = 'DeepDOC',
  PlainText = 'Plain Text',
  MinerU = 'MinerU',
}

const parseMethodOptions = [
  { label: 'auto', value: 'auto' },
  { label: 'txt', value: 'txt' },
  { label: 'ocr', value: 'ocr' },
];

const languageOptions = [
  'English',
  'Chinese',
  'Traditional Chinese',
  'Russian',
  'Ukrainian',
  'Indonesian',
  'Spanish',
  'Vietnamese',
  'Japanese',
  'Korean',
  'Portuguese BR',
  'German',
  'French',
  'Italian',
  'Tamil',
  'Telugu',
  'Kannada',
  'Thai',
  'Greek',
  'Hindi',
].map((value) => ({ label: value, value }));

const MinerUOptions = () => {
  const { t } = useTranslate('knowledgeDetails');
  const layoutRecognize = Form.useWatch(['parser_config', 'layout_recognize']);
  const isMinerUSelected =
    typeof layoutRecognize === 'string' &&
    layoutRecognize.toLowerCase().includes('mineru');

  if (!isMinerUSelected) {
    return null;
  }

  return (
    <div className="border-l-2 border-primary/30 pl-4 ml-2 space-y-4">
      <div className="text-sm font-medium text-muted-foreground">
        {t('mineruOptions', 'MinerU Options')}
      </div>
      <Form.Item
        name={['parser_config', 'mineru_parse_method']}
        label={t('mineruParseMethod', 'Parse method')}
        initialValue="auto"
      >
        <Select options={parseMethodOptions} />
      </Form.Item>
      <Form.Item
        name={['parser_config', 'mineru_lang']}
        label={t('mineruLanguage', 'Language')}
        initialValue="English"
      >
        <Select options={languageOptions} />
      </Form.Item>
      <Form.Item
        name={['parser_config', 'mineru_formula_enable']}
        label={t('mineruFormulaEnable', 'Formula recognition')}
        valuePropName="checked"
        initialValue={true}
      >
        <Switch defaultChecked />
      </Form.Item>
      <Form.Item
        name={['parser_config', 'mineru_table_enable']}
        label={t('mineruTableEnable', 'Table recognition')}
        valuePropName="checked"
        initialValue={true}
      >
        <Switch defaultChecked />
      </Form.Item>
    </div>
  );
};

const LayoutRecognize = () => {
  const { t } = useTranslate('knowledgeDetails');
  const allOptions = useSelectLlmOptionsByModelType();

  const options = useMemo(() => {
    const list = [
      DocumentType.DeepDOC,
      DocumentType.PlainText,
      DocumentType.MinerU,
    ].map((x) => ({
      label:
        x === DocumentType.PlainText
          ? t(camelCase(x))
          : x === DocumentType.DeepDOC
            ? 'DeepDoc'
            : x,
      value: x,
    }));

    const image2TextList = [
      ...allOptions[LlmModelType.Image2text],
      ...allOptions[LlmModelType.Ocr],
    ].map((x) => {
      return {
        ...x,
        options: x.options.map((y) => {
          return {
            ...y,
            label: (
              <div className="flex justify-between items-center gap-2">
                {y.label}
                <span className="text-red-500 text-sm">Experimental</span>
              </div>
            ),
          };
        }),
      };
    });

    return [...list, ...image2TextList];
  }, [allOptions, t]);

  return (
    <>
      <Form.Item
        name={['parser_config', 'layout_recognize']}
        label={t('layoutRecognize')}
        initialValue={DocumentType.DeepDOC}
        tooltip={t('layoutRecognizeTip')}
      >
        <Select options={options} popupMatchSelectWidth={false} />
      </Form.Item>
      <MinerUOptions />
    </>
  );
};

export default LayoutRecognize;
